import React, { useState } from 'react';

function Contact({ data }) {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });
  const [status, setStatus] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatus('');

    try {
      const response = await fetch('http://localhost:5001/api/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const result = await response.json();

      if (result.success) {
        setStatus('success');
        setFormData({ name: '', email: '', message: '' });
        // Show success message for 5 seconds
        setTimeout(() => setStatus(''), 5000);
      } else {
        setStatus(`error: ${result.error}`);
      }
    } catch (error) {
      console.error('Error sending message:', error);
      setStatus(`error: Could not connect to server at localhost:5001. Make sure backend is running.`);
    } finally {
      setLoading(false);
    }
  };

  if (!data) return null;

  return (
    <section id="contact" className="py-12 md:py-16 bg-[#f6f1e7]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#7b7367] font-semibold mb-3">
            Get in Touch
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#1d1c19]"
            style={{ fontFamily: '"Playfair Display", "Times New Roman", serif', fontWeight: 700 }}
          >
            Let us build something
          </h2>
        </div>

        <div className="grid md:grid-cols-2 gap-12">
          <div className="rounded-3xl border border-[#ddd3c5] bg-white p-6 md:p-7 shadow-[0_14px_35px_rgba(17,17,17,0.06)]">
            <p className="text-sm font-black text-[#1f1d1a] mb-8 uppercase tracking-[0.2em]">Contact Information</p>
            <div className="space-y-8">
              <div className="border-b border-[#ebe3d8] pb-8">
                <p className="text-[10px] uppercase tracking-[0.28em] text-[#7d7567] font-semibold mb-2">Email</p>
                <a href={`mailto:${data.email}`} className="text-base text-[#1f1d1a] hover:text-[#5f574d]">
                  {data.email}
                </a>
              </div>
              <div className="border-b border-[#ebe3d8] pb-8">
                <p className="text-[10px] uppercase tracking-[0.28em] text-[#7d7567] font-semibold mb-2">Phone</p>
                <a href={`tel:${data.phone}`} className="text-base text-[#1f1d1a] hover:text-[#5f574d]">
                  {data.phone}
                </a>
              </div>
              <div>
                <p className="text-[10px] uppercase tracking-[0.28em] text-[#7d7567] font-semibold mb-2">LinkedIn</p>
                <a href={data.linkedin} target="_blank" rel="noopener noreferrer" className="text-base text-[#1f1d1a] hover:text-[#5f574d]">
                  Connect with me
                </a>
              </div>

              <div className="pt-4 border-t border-[#ebe3d8]">
                <div className="flex flex-wrap gap-6 text-sm md:text-base font-medium">
                  <a href="https://instagram.com" target="_blank" rel="noopener noreferrer" className="text-[#1f1d1a] hover:text-[#5f574d] transition flex items-center gap-1">
                    Instagram <span aria-hidden="true">↗</span>
                  </a>
                  <a href={`mailto:${data.email}`} className="text-[#6f685c] hover:text-[#1f1d1a] transition flex items-center gap-1">
                    Email <span aria-hidden="true">↗</span>
                  </a>
                  <a href={data.linkedin} target="_blank" rel="noopener noreferrer" className="text-[#6f685c] hover:text-[#1f1d1a] transition flex items-center gap-1">
                    Linkedin <span aria-hidden="true">↗</span>
                  </a>
                  <a href="https://x.com" target="_blank" rel="noopener noreferrer" className="text-[#6f685c] hover:text-[#1f1d1a] transition flex items-center gap-1">
                    x (Twitter) <span aria-hidden="true">↗</span>
                  </a>
                </div>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6 rounded-3xl border border-[#ddd3c5] bg-white p-6 md:p-7 shadow-[0_14px_35px_rgba(17,17,17,0.06)]">
            <div>
              <label className="block text-[10px] uppercase tracking-[0.28em] text-[#7d7567] font-semibold mb-3">Name</label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleChange}
                required
                className="w-full px-4 py-3 rounded-xl border border-[#d8cdbd] text-[#1f1d1a] placeholder-[#9a9286] focus:outline-none focus:border-[#1f1d1a]"
                placeholder="Your Name"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase tracking-[0.28em] text-[#7d7567] font-semibold mb-3">Email</label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                className="w-full px-4 py-3 rounded-xl border border-[#d8cdbd] text-[#1f1d1a] placeholder-[#9a9286] focus:outline-none focus:border-[#1f1d1a]"
                placeholder="your@email.com"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase tracking-[0.28em] text-[#7d7567] font-semibold mb-3">Message</label>
              <textarea
                name="message"
                value={formData.message}
                onChange={handleChange}
                required
                rows="4"
                className="w-full px-4 py-3 rounded-xl border border-[#d8cdbd] text-[#1f1d1a] placeholder-[#9a9286] focus:outline-none focus:border-[#1f1d1a]"
                placeholder="Your message here..."
              ></textarea>
            </div>
            <button
              type="submit"
              disabled={loading}
              className="w-full rounded-xl bg-[#1f1d1a] text-white font-black py-3.5 uppercase tracking-[0.2em] hover:bg-[#37332c] transition disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? 'Sending...' : 'Send Message'}
            </button>
            
            {/* Status Messages */}
            {status === 'success' && (
              <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded">
                Message sent successfully! I'll get back to you soon.
              </div>
            )}
            {status.startsWith('error') && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded">
                {status.replace('error: ', '')}
              </div>
            )}
          </form>
        </div>
      </div>
    </section>
  );
}

export default Contact;
